		@Bean
		public OpenAiApi openAiApi() {
			String apiKey = System.getenv("OPENAI_API_KEY");
			if (!StringUtils.hasText(apiKey)) {
				throw new IllegalArgumentException(
						"You must provide an API key.  Put it in an environment variable under the name OPENAI_API_KEY");
			}

			return OpenAiApi.builder().apiKey(apiKey).build();
		}

		@Bean
		public OpenAiChatModel openAiChatModel(OpenAiApi api, ToolCallingManager toolCallingManager) {
			return OpenAiChatModel.builder()
				.openAiApi(api)
				.defaultOptions(OpenAiChatOptions.builder().model(OpenAiApi.ChatModel.GPT_4_O_MINI).build())
				.retryTemplate(RetryUtils.DEFAULT_RETRY_TEMPLATE)
				.toolCallingManager(toolCallingManager)
				.build();
		}

		@Bean
		@ConditionalOnMissingBean
		ToolCallingManager toolCallingManager(ToolCallbackResolver toolCallbackResolver,
				ToolExecutionExceptionProcessor toolExecutionExceptionProcessor,
				ObjectProvider<ObservationRegistry> observationRegistry) {
			return ToolCallingManager.builder()
				.observationRegistry(observationRegistry.getIfUnique(() -> ObservationRegistry.NOOP))
				.toolCallbackResolver(toolCallbackResolver)
				.toolExecutionExceptionProcessor(toolExecutionExceptionProcessor)
				.build();
		}

		@Bean
		@ConditionalOnMissingBean
		ToolCallbackResolver toolCallbackResolver(GenericApplicationContext applicationContext,
				List<ToolCallback> toolCallbacks, List<ToolCallbackProvider> tcbProviders) {

			List<ToolCallback> allFunctionAndToolCallbacks = new ArrayList<>(toolCallbacks);
			tcbProviders.stream()
				.map(pr -> List.of(pr.getToolCallbacks()))
				.forEach(allFunctionAndToolCallbacks::addAll);

			var staticToolCallbackResolver = new StaticToolCallbackResolver(allFunctionAndToolCallbacks);

			var springBeanToolCallbackResolver = SpringBeanToolCallbackResolver.builder()
				.applicationContext(applicationContext)
				.build();

			return new DelegatingToolCallbackResolver(
					List.of(staticToolCallbackResolver, springBeanToolCallbackResolver));
		}

		@Bean
		@ConditionalOnMissingBean
		ToolExecutionExceptionProcessor toolExecutionExceptionProcessor() {
			return new DefaultToolExecutionExceptionProcessor(false);
		}

		@Bean
		public OpenAiEmbeddingModel openAiEmbeddingModel(OpenAiApi api) {
			return new OpenAiEmbeddingModel(api);
		}

		@Bean
		@ConditionalOnMissingBean
		public SpringBeanToolCallbackResolver springAiFunctionManager(ApplicationContext context) {
			return SpringBeanToolCallbackResolver.builder()
				.applicationContext((GenericApplicationContext) context)
				.build();
		}

		@Bean
		public VectorStore vectorStore(EmbeddingModel embeddingModel, ChromaApi chromaApi) {
			return ChromaVectorStore.builder(chromaApi, embeddingModel).initializeSchema(true).build();
		}

		@Bean
		public ChromaApi chromaApi() {
			String chromaDbHost = chromadb.getHost();
			int chromaDbPort = chromadb.getMappedPort(8000); // Adjust port if necessary

			String baseUrl = String.format("http://%s:%d", chromaDbHost, chromaDbPort);
			return ChromaApi.builder().baseUrl(baseUrl).build();
		}

	}

